const ENVIRONMENT_WEB_URLS = {
  production: 'https://cn.designflow.app',
  'sandbox-albert': 'https://alsand.designflow.app',
  sandbox: 'https://sandbox.designflow.app',
};

function trimTrailingSlash(url) {
  return url ? String(url).replace(/\/+$/, '') : '';
}

function getWebUrl(env = process.env.NODE_ENV, configuredUrl = process.env.WEB_URL) {
  const environment = String(env || '').toLowerCase();

  if (ENVIRONMENT_WEB_URLS[environment]) {
    return ENVIRONMENT_WEB_URLS[environment];
  }

  return trimTrailingSlash(configuredUrl);
}

module.exports = {
  getWebUrl,
};

