const { getWebUrl } = require('../../helpers/web-url');

describe('getWebUrl', () => {
  test('uses the public Albert sandbox hostname for sandbox-albert', () => {
    expect(getWebUrl('sandbox-albert', 'https://sandbox-albert.designflow.app')).toBe('https://alsand.designflow.app');
  });

  test('uses the production vendor hostname for production', () => {
    expect(getWebUrl('production', 'https://designflow.app')).toBe('https://cn.designflow.app');
  });

  test('uses the shared sandbox hostname for sandbox', () => {
    expect(getWebUrl('sandbox', 'https://wrong.example')).toBe('https://sandbox.designflow.app');
  });

  test('falls back to configured WEB_URL for unknown environments', () => {
    expect(getWebUrl('localhost', 'http://localhost:4200/')).toBe('http://localhost:4200');
  });
});

