const URL_ALIASES = {
  'https://sandbox-albert.designflow.app': 'https://alsand.designflow.app',
};

function trimTrailingSlash(url) {
  return url ? String(url).replace(/\/+$/, '') : '';
}

function getWebUrl(env = process.env.NODE_ENV, configuredUrl = process.env.WEB_URL, options = {}) {
  const environment = String(env || '').toLowerCase();

  if (options.vendorHost && environment === 'production') {
    return 'https://cn.designflow.app';
  }

  if (ENVIRONMENT_WEB_URLS[environment]) {
    return ENVIRONMENT_WEB_URLS[environment];
  }

  const normalizedConfiguredUrl = trimTrailingSlash(configuredUrl);
  return URL_ALIASES[normalizedConfiguredUrl] || normalizedConfiguredUrl;
}

module.exports = {
  getWebUrl,
};
