  });

  test('uses the shared sandbox hostname for sandbox', () => {
    expect(getWebUrl('sandbox', 'https://wrong.example')).toBe('https://sandbox.designflow.app');
  });

  test('falls back to configured WEB_URL for unknown environments', () => {
    expect(getWebUrl('localhost', 'http://localhost:4200/')).toBe('http://localhost:4200');
  });

  test('aliases the old Albert sandbox hostname even without NODE_ENV', () => {
